  // === FRANK AI CHAT CLASS ===
/**
 * Frank AI Chat Client
 * Handles real-time chat with the Mortgage AI API
 */

class FrankAIChat {
  constructor(config = {}) {
    // Configuration (for standalone widget usage)
    this.container = config.container || document;
    this.apiEndpoint = config.apiEndpoint || '/api/ai/chat';
    this.authToken = config.authToken || null;
    this.enablePersistence = config.enablePersistence !== false;
    
    // State
    this.messages = [];
    this.sessionState = null;
    this.isStreaming = false;
    this.currentMessageElement = null;
    this.conversationId = this.generateConversationId();
    this.initialized = false;
    this.isLocked = true;
    this.lockedTooltipTimer = null;
    
    // Load persisted conversation from sessionStorage
    if (this.enablePersistence) {
      this.loadConversation();
    }
    
    // DOM elements (query from container, not document)
    this.chatBubble = this.container.getElementById('frankChatBubble');
    this.chatBadge = this.container.getElementById('frankChatBadge');
    this.chatPanel = this.container.getElementById('frankPanel');
    this.closeBtn = this.container.getElementById('frankCloseBtn');
    this.messagesContainer = this.container.querySelector('.frank-messages');
    this.inputField = this.container.querySelector('.frank-input-field');
    this.sendBtn = this.container.querySelector('.frank-send-btn');
    this.lockedTooltip = this.container.getElementById('frankLockedTooltip');
    
    // Call init but don't await - it will bind events asynchronously
    this.init().catch(error => {
      console.error('❌ Failed to initialize chat:', error);
    });
  }
  
  async init() {
    // Always bind event listeners first, before auth check
    this.bindEvents();
    
    console.log('🔐 Init - authToken:', this.authToken);
    
    // Check if user is authenticated (only if authToken not provided in config)
    if (!this.authToken) {
      console.log('🔍 No authToken found, checking authentication...');
      await this.checkAuthentication();
    } else {
      console.log('✅ AuthToken provided, skipping authentication check');
    }
    
    const shouldLock = !this.authToken;
    console.log('🔒 Should lock?', shouldLock);
    this.setLockedState(shouldLock);
    
    if (!shouldLock) {
      // Restore previous messages to UI
      this.restoreMessages();
    }
    
    this.initialized = true;
  }
  
  loadConversation() {
    try {
      const saved = sessionStorage.getItem('frankChatConversation');
      if (saved) {
        const data = JSON.parse(saved);
        this.messages = data.messages || [];
        this.sessionState = data.sessionState || null;
        this.conversationId = data.conversationId || this.conversationId;
      }
    } catch (error) {
      console.error('Failed to load conversation:', error);
    }
  }

  setLockedState(isLocked) {
    this.isLocked = isLocked;
    if (this.chatBubble) {
      this.chatBubble.style.display = 'flex';
      this.chatBubble.classList.toggle('locked', isLocked);
      this.chatBubble.setAttribute('aria-disabled', isLocked ? 'true' : 'false');
    }
    if (this.chatBadge) {
      this.chatBadge.setAttribute('aria-disabled', isLocked ? 'true' : 'false');
    }
    if (this.inputField) {
      this.inputField.disabled = isLocked;
      this.inputField.placeholder = isLocked
        ? 'Start your application to unlock Frankie'
        : 'Ask Frankie anything...';
    }
    if (this.sendBtn) {
      this.sendBtn.disabled = isLocked;
    }
    if (!isLocked && this.lockedTooltip) {
      this.lockedTooltip.classList.remove('visible');
    }
  }

  showLockedTooltip() {
    if (!this.lockedTooltip) return;
    this.lockedTooltip.classList.add('visible');
    if (this.lockedTooltipTimer) {
      clearTimeout(this.lockedTooltipTimer);
    }
    this.lockedTooltipTimer = setTimeout(() => {
      this.lockedTooltip?.classList.remove('visible');
    }, 2500);
  }

  nudgeLauncher() {
    if (!this.chatBubble) return;
    this.chatBubble.classList.remove('pulse');
    void this.chatBubble.offsetWidth;
    this.chatBubble.classList.add('pulse');
    if (this.isLocked) {
      this.showLockedTooltip();
    }
  }
  
  saveConversation() {
    try {
      const data = {
        messages: this.messages,
        sessionState: this.sessionState,
        conversationId: this.conversationId,
        timestamp: Date.now()
      };
      sessionStorage.setItem('frankChatConversation', JSON.stringify(data));
      console.log('💾 Saved conversation to storage');
    } catch (error) {
      console.error('Failed to save conversation:', error);
    }
  }
  
  restoreMessages() {
    if (!this.messagesContainer || this.messages.length === 0) return;
    
    console.log('🔄 Restoring', this.messages.length, 'messages to UI');
    
    // Clear existing messages
    this.messagesContainer.innerHTML = '';
    
    // Render each message
    this.messages.forEach(msg => {
      if (msg.role === 'user') {
        this.appendUserMessage(msg.content, false); // Don't save again
      } else if (msg.role === 'assistant') {
        const messageElement = this.createAssistantMessage();
        const textElement = messageElement.querySelector('.message-text');
        
        // Render as markdown
        if (typeof marked !== 'undefined') {
          try {
            const rendered = typeof marked.parse === 'function' ? marked.parse(msg.content) : marked(msg.content);
            textElement.innerHTML = rendered;
          } catch (e) {
            console.error('Markdown parsing error:', e);
            textElement.textContent = msg.content;
          }
        } else {
          textElement.textContent = msg.content;
        }
      }
    });
    
    this.scrollToBottom();
  }
  
  bindEvents() {
    if (this.chatBubble) {
      this.chatBubble.addEventListener('click', () => {
        if (this.isLocked) {
          this.showLockedTooltip();
          return;
        }
        this.openChat();
      });
    } else {
      console.error('❌ Chat bubble not found!');
    }

    if (this.chatBadge) {
      const triggerOpen = (event) => {
        event?.preventDefault();
        if (this.isLocked) {
          this.showLockedTooltip();
          return;
        }
        this.openChat();
      };
      this.chatBadge.addEventListener('click', triggerOpen);
      this.chatBadge.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' || e.key === ' ') {
          triggerOpen(e);
        }
      });
    }
    
    // Initialize resize functionality
    this.initResize();
    
    if (this.closeBtn) {
      this.closeBtn.addEventListener('click', () => {
        this.closeChat();
      });
    } else {
      console.error('❌ Close button not found!');
    }
    
    if (this.sendBtn) {
      this.sendBtn.addEventListener('click', (e) => {
        try {
          this.sendMessage();
        } catch (error) {
          console.error('❌ Error in sendMessage:', error);
        }
      });
    } else {
      console.error('❌ Send button not found!');
    }
    
    if (this.inputField) {
      this.inputField.addEventListener('keypress', (e) => {
        if (e.key === 'Enter' && !e.shiftKey) {
          e.preventDefault();
          try {
            this.sendMessage();
          } catch (error) {
            console.error('❌ Error in sendMessage:', error);
          }
        }
      });
    } else {
      console.error('❌ Input field not found!');
    }
  }
  
  async checkAuthentication() {
    try {
      console.log('🔐 Checking authentication...');
      const response = await fetch('/api/auth/me', {
        method: 'GET',
        credentials: 'include'
      });
      
      if (response.ok) {
        const data = await response.json();
        if (data.authenticated) {
          console.log('✅ User authenticated:', data);
          // Store user info if needed
          this.user = data.user;
          this.authToken = true; // We use session cookies, so just flag as authenticated
        } else {
          console.log('⚠️ User not authenticated');
          this.authToken = null;
        }
      } else {
        console.log('⚠️ User not authenticated');
        this.authToken = null;
      }
    } catch (error) {
      console.error('❌ Auth check failed:', error);
      this.authToken = null;
    }
  }
  
  // Public method to manually enable chat (call after user submits initial form)
  enableChat() {
    console.log('🔓 Enabling chat manually...');
    this.authToken = true;
    this.setLockedState(false);
    if (this.chatBubble) {
      this.chatBubble.style.display = 'flex';
      console.log('✅ Chat bubble now visible');
    }
    this.restoreMessages();
  }
  
  generateConversationId() {
    return `conv-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }
  
  openChat() {
    if (this.isLocked) {
      this.showLockedTooltip();
      return;
    }
    this.chatPanel?.classList.add('open');
    if (this.chatBadge) {
      this.chatBadge.classList.add('hidden');
    }
    
    // Hide notification badge
    const notification = document.querySelector('.frank-notification');
    if (notification) {
      notification.style.display = 'none';
    }
    
    // Focus input
    this.inputField?.focus();
  }
  
  closeChat() {
    this.chatPanel?.classList.remove('open');
    if (this.chatBadge) {
      this.chatBadge.classList.remove('hidden');
    }
  }
  
  initResize() {
    if (!this.chatPanel) return;
    
    // Get maximize/minimize button from template
    const maxBtn = this.container.getElementById('frankMaximizeBtn');
    
    if (!maxBtn) {
      console.warn('⚠️ Maximize button not found in template');
      return;
    }
    
    let isMaximized = false;
    
    maxBtn.addEventListener('click', () => {
      if (isMaximized) {
        // Restore to normal size
        this.chatPanel.style.width = '400px';
        this.chatPanel.style.height = '500px';
        this.chatPanel.style.maxWidth = '400px';
        this.chatPanel.style.right = '0';
        this.chatPanel.style.bottom = '0';
        this.chatPanel.style.borderRadius = 'var(--radius-xl) var(--radius-xl) 0 0';
        maxBtn.innerHTML = `<svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
          <path d="M2 2h5v2H4v3H2V2zm7 0h5v5h-2V4h-3V2zM4 11v-3H2v5h5v-2H4zm9-3v3h-3v2h5v-5h-2z" fill="currentColor"/>
        </svg>`;
        maxBtn.title = 'Maximize';
        isMaximized = false;
      } else {
        // Maximize
        this.chatPanel.style.width = '95vw';
        this.chatPanel.style.height = '95vh';
        this.chatPanel.style.maxWidth = '95vw';
        this.chatPanel.style.right = '2.5vw';
        this.chatPanel.style.bottom = '2.5vh';
        this.chatPanel.style.borderRadius = 'var(--radius-xl)';
        maxBtn.innerHTML = `<svg width="16" height="16" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg">
          <path d="M3 3v3H1V1h5v2H3zm10 0h-3V1h5v5h-2V3zM3 13h3v2H1v-5h2v3zm10 0v-3h2v5h-5v-2h3z" fill="currentColor"/>
        </svg>`;
        maxBtn.title = 'Restore';
        isMaximized = true;
      }
    });
  }
  
  async sendMessage() {
    console.log('📤 sendMessage called');
    if (this.isLocked) {
      this.showLockedTooltip();
      return;
    }
    const text = this.inputField?.value.trim();
    
    console.log('Input field value:', text);
    console.log('Is streaming:', this.isStreaming);
    
    if (!text || this.isStreaming) {
      console.log('❌ Cannot send:', { hasText: !!text, isStreaming: this.isStreaming });
      return;
    }
    
    console.log('✅ Sending message:', text);
    
    // Clear input
    this.inputField.value = '';
    
    // Add user message to UI
    this.appendUserMessage(text);
    
    // Add to messages array
    this.messages.push({
      role: 'user',
      content: text
    });
    
    // Show typing indicator
    this.showTypingIndicator();
    
    try {
      // Call API with streaming
      await this.callChatAPI(true);
    } catch (error) {
      console.error('❌ Chat error:', error);
      this.hideTypingIndicator();
      if (error.isRateLimit) {
        const secs = error.retryAfter || 60;
        const waitLabel = secs >= 60
          ? `${Math.ceil(secs / 60)} minute${Math.ceil(secs / 60) > 1 ? 's' : ''}`
          : `${secs} second${secs !== 1 ? 's' : ''}`;
        this.appendErrorMessage(`⏳ You've sent too many messages. Please wait ${waitLabel} and try again.`);
      } else {
        this.appendErrorMessage('Sorry, I encountered an error. Please try again.');
      }
    }
  }
  
  async callChatAPI(stream = true) {
    this.isStreaming = true;
    
    const requestBody = {
      messages: this.messages,
      context: {
        overrides: {
          retrieval_mode: 'hybrid',
          semantic_ranker: true,
          top: 3,
          temperature: 0.3,
          suggest_followup_questions: true
        }
      },
      session_state: this.sessionState || {},
      stream: stream
    };
    
    try {
      
      // Use auth token from constructor config or session storage
      const authToken = this.authToken || sessionStorage.getItem('auth_token');
      const headers = {
        'Content-Type': 'application/json'
      };
      
      // Add Bearer token if available (for OTP authentication)
      if (authToken) {
        headers['Authorization'] = `Bearer ${authToken}`;
        console.log('🔐 Including Bearer token in request');
      } else {
        console.log('🍪 Relying on session cookie authentication');
      }
      
      const response = await fetch(this.apiEndpoint, {
        method: 'POST',
        headers: headers,
        body: JSON.stringify(requestBody),
        credentials: 'include' // Include cookies for session-based auth
      });
      
      console.log('📥 Response received:', {
        ok: response.ok,
        status: response.status,
        statusText: response.statusText,
        contentType: response.headers.get('content-type')
      });
      
      if (!response.ok) {
        if (response.status === 429) {
          const retryAfter = parseInt(response.headers.get('Retry-After') || '60', 10);
          const err = new Error('rate_limited');
          err.isRateLimit = true;
          err.retryAfter = retryAfter;
          throw err;
        }
        const errorText = await response.text();
        console.error('❌ API error response:', errorText);
        throw new Error(`API error: ${response.status} ${response.statusText}`);
      }
      
      if (stream) {
        console.log('📺 Handling streaming response...');
        await this.handleStreamingResponse(response);
      } else {
        console.log('📄 Handling non-streaming response...');
        const data = await response.json();
        this.handleNonStreamingResponse(data);
      }
    } catch (error) {
      console.error('❌ API call failed:', error);
      throw error;
    } finally {
      this.isStreaming = false;
    }
  }
  
  async handleStreamingResponse(response) {
    this.hideTypingIndicator();
    
    // Create assistant message element
    this.currentMessageElement = this.createAssistantMessage();
    const textElement = this.currentMessageElement.querySelector('.message-text');
    
    let assistantMessage = '';
    let buffer = '';
    
    const reader = response.body.getReader();
    const decoder = new TextDecoder();
    
    try {
      while (true) {
        const { done, value } = await reader.read();
        
        if (done) {
          // Process any remaining buffer
          if (buffer.trim()) {
            this.processStreamChunk(buffer, textElement, (msg) => assistantMessage = msg);
          }
          
          // Stream complete - render final markdown
          if (assistantMessage && typeof marked !== 'undefined') {
            try {
              const rendered = typeof marked.parse === 'function' ? marked.parse(assistantMessage) : marked(assistantMessage);
              textElement.innerHTML = rendered;
            } catch (e) {
              console.error('Markdown parsing error:', e);
            }
          }
          
          break;
        }
        
        // Decode chunk and add to buffer
        buffer += decoder.decode(value, { stream: true });
        
        // Process complete lines (NDJSON format)
        const lines = buffer.split('\n');
        buffer = lines.pop() || ''; // Keep incomplete line in buffer
        
        for (const line of lines) {
          if (line.trim()) {
            this.processStreamChunk(line, textElement, (msg) => assistantMessage = msg);
          }
        }
      }
    } catch (error) {
      console.error('Stream reading error:', error);
      throw error;
    }
    
    // Add complete message to history
    if (assistantMessage) {
      this.messages.push({
        role: 'assistant',
        content: assistantMessage
      });
      this.saveConversation();
    }
  }
  
  processStreamChunk(line, textElement, updateMessage) {
    try {
      const data = JSON.parse(line);
      
      // Handle delta chunks (streaming text)
      if (data.delta && data.delta.content) {
        const currentText = textElement.textContent || '';
        const newText = currentText + data.delta.content;
        
        // During streaming, show plain text
        textElement.textContent = newText;
        updateMessage(newText);
        
        // Auto-scroll to bottom
        this.scrollToBottom();
      }
      
      // Handle context (citations, follow-ups, session state)
      if (data.context) {
        this.handleContext(data.context, this.currentMessageElement);
      }
      
      // Update session state
      if (data.session_state) {
        this.sessionState = data.session_state;
      }
    } catch (error) {
      console.error('Failed to parse NDJSON line:', line, error);
    }
  }
  
  handleNonStreamingResponse(data) {
    this.hideTypingIndicator();
    
    if (data.message && data.message.content) {
      const messageElement = this.createAssistantMessage();
      const textElement = messageElement.querySelector('.message-text');
      
      // Render as markdown if marked.js is available
      if (typeof marked !== 'undefined') {
        try {
          const rendered = typeof marked.parse === 'function' ? marked.parse(data.message.content) : marked(data.message.content);
          textElement.innerHTML = rendered;
        } catch (e) {
          console.error('Markdown parsing error:', e);
          textElement.textContent = data.message.content;
        }
      } else {
        textElement.textContent = data.message.content;
      }
      
      // Add to history
      this.messages.push({
        role: 'assistant',
        content: data.message.content
      });
      this.saveConversation();
      
      // Handle context
      if (data.context) {
        this.handleContext(data.context, messageElement);
      }
      
      // Update session state
      if (data.session_state) {
        this.sessionState = data.session_state;
      }
      
      this.scrollToBottom();
    }
  }
  
  handleContext(context, messageElement) {
    // Handle adaptive cards (replace with friendly message)
    if (context.ui_component) {
      this.handleAdaptiveCardFallback(context.ui_component, messageElement);
      return; // Don't show citations/followups when showing adaptive card message
    }
    
    // Handle citations
    if (context.data_points && context.data_points.length > 0) {
      this.appendCitations(context.data_points, messageElement);
    }
    
    // Handle follow-up questions
    if (context.followup_questions && context.followup_questions.length > 0) {
      this.appendFollowUpQuestions(context.followup_questions, messageElement);
    }
  }
  
  handleAdaptiveCardFallback(uiComponent, messageElement) {
    // Detect what type of calculator/tool the AI is trying to provide
    const componentId = uiComponent.id || '';
    const componentTitle = uiComponent.title || '';
    
    let friendlyMessage = '';
    
    // GDS/TDS Calculator
    if (componentId.includes('gds') || componentId.includes('tds') || 
        componentTitle.toLowerCase().includes('gds') || componentTitle.toLowerCase().includes('tds') ||
        componentTitle.toLowerCase().includes('ratio')) {
      friendlyMessage = `\n\n📊 **Great question about GDS/TDS ratios!**\n\nGood news - this mortgage application automatically calculates your ratios as you fill out the form. Just complete the financial sections and we'll show you your GDS and TDS percentages along with qualification details.\n\nAny other questions about mortgages I can help you with?`;
    }
    // Affordability Calculator
    else if (componentId.includes('affordability') || componentTitle.toLowerCase().includes('affordability') ||
             componentTitle.toLowerCase().includes('how much')) {
      friendlyMessage = `\n\n🏠 **Wondering how much you can afford?**\n\nPerfect timing! As you work through this application and enter your income and financial details, we'll calculate your maximum purchase price and show you personalized mortgage options at the end.\n\nAny other questions about mortgages I can help you with?`;
    }
    // Mortgage Calculator
    else if (componentId.includes('mortgage') || componentId.includes('calculator') ||
             componentTitle.toLowerCase().includes('calculate') || componentTitle.toLowerCase().includes('payment')) {
      friendlyMessage = `\n\n💰 **Need to calculate mortgage payments?**\n\nThe application has built-in calculators that will show you estimated monthly payments based on the property value and mortgage details you enter. Just keep filling out the form and you'll see the calculations automatically!\n\nAny other questions about mortgages I can help you with?`;
    }
    // Comparison Tool
    else if (componentId.includes('comparison') || componentId.includes('compare') ||
             componentTitle.toLowerCase().includes('compare')) {
      friendlyMessage = `\n\n📈 **Looking to compare options?**\n\nOnce you complete your application, we'll present multiple mortgage products side-by-side with rates, terms, and monthly payments so you can easily compare and choose the best option for you.\n\nAny other questions about mortgages I can help you with?`;
    }
    // Generic fallback
    else {
      friendlyMessage = `\n\n✨ **I see you're looking for interactive tools!**\n\nThis mortgage application includes all the calculators and tools you need built right into the form. As you complete each step, you'll see relevant calculations and comparisons automatically. Just keep going - I'm here if you have questions!`;
    }
    
    // Append the friendly fallback message to the existing message text as markdown
    const messageText = messageElement.querySelector('.message-text');
    if (messageText) {
      // Get current content (could be text or HTML)
      const currentContent = messageText.textContent || '';
      const combinedContent = currentContent + friendlyMessage;
      
      // Re-render with markdown
      if (typeof marked !== 'undefined') {
        try {
          const rendered = typeof marked.parse === 'function' ? marked.parse(combinedContent) : marked(combinedContent);
          messageText.innerHTML = rendered;
        } catch (e) {
          console.error('Markdown parsing error:', e);
          messageText.textContent = combinedContent;
        }
      } else {
        messageText.textContent = combinedContent;
      }
    }
  }
  
  appendUserMessage(text, saveToHistory = true) {
    const messageDiv = document.createElement('div');
    messageDiv.className = 'frank-message user-message';
    messageDiv.innerHTML = `
      <div class="message-bubble user-bubble">
        <div class="message-text">${this.escapeHtml(text)}</div>
      </div>
    `;
    
    this.messagesContainer.appendChild(messageDiv);
    this.scrollToBottom();
    
    // Save to conversation history
    if (saveToHistory) {
      this.saveConversation();
    }
  }
  
  createAssistantMessage() {
    const messageDiv = document.createElement('div');
    messageDiv.className = 'frank-message assistant-message';
    messageDiv.innerHTML = `
      <div class="message-avatar" aria-hidden="true"></div>
      <div class="message-bubble">
        <div class="message-text"></div>
      </div>
    `;
    
    this.messagesContainer.appendChild(messageDiv);
    return messageDiv;
  }
  
  appendCitations(citations, messageElement) {
    const citationsDiv = document.createElement('div');
    citationsDiv.className = 'message-citations';
    citationsDiv.innerHTML = `
      <div class="citations-header">📚 Sources:</div>
      ${citations.slice(0, 3).map((citation, index) => `
        <div class="citation-item">
          <span class="citation-number">[${index + 1}]</span>
          <span class="citation-text">${this.escapeHtml(citation.substring(0, 100))}${citation.length > 100 ? '...' : ''}</span>
        </div>
      `).join('')}
    `;
    
    const bubble = messageElement.querySelector('.message-bubble');
    bubble.appendChild(citationsDiv);
  }
  
  appendFollowUpQuestions(questions, messageElement) {
    const questionsDiv = document.createElement('div');
    questionsDiv.className = 'followup-questions';
    questionsDiv.innerHTML = `
      <div class="followup-header">You might also ask:</div>
      ${questions.slice(0, 3).map(q => `
        <button class="followup-btn" data-question="${this.escapeHtml(q)}">
          ${this.escapeHtml(q)}
        </button>
      `).join('')}
    `;
    
    // Add click handlers
    questionsDiv.querySelectorAll('.followup-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        const question = btn.getAttribute('data-question');
        this.inputField.value = question;
        this.sendMessage();
      });
    });
    
    const bubble = messageElement.querySelector('.message-bubble');
    bubble.appendChild(questionsDiv);
  }
  
  appendErrorMessage(text) {
    const messageDiv = document.createElement('div');
    messageDiv.className = 'frank-message assistant-message error-message';
    messageDiv.innerHTML = `
      <div class="message-avatar" aria-hidden="true"></div>
      <div class="message-bubble">
        <div class="message-text">${this.escapeHtml(`⚠️ ${text}`)}</div>
      </div>
    `;
    
    this.messagesContainer.appendChild(messageDiv);
    this.scrollToBottom();
  }
  
  showTypingIndicator() {
    const indicator = document.createElement('div');
    indicator.className = 'frank-message typing-indicator';
    indicator.id = 'typingIndicator';
    indicator.innerHTML = `
      <div class="message-avatar" aria-hidden="true"></div>
      <div class="message-bubble">
        <div class="typing-dots">
          <span></span><span></span><span></span>
        </div>
      </div>
    `;
    
    this.messagesContainer.appendChild(indicator);
    this.scrollToBottom();
  }
  
  hideTypingIndicator() {
    const indicator = this.container.getElementById('typingIndicator');
    if (indicator) {
      indicator.remove();
    }
  }
  
  scrollToBottom() {
    if (this.messagesContainer) {
      this.messagesContainer.scrollTop = this.messagesContainer.scrollHeight;
    }
  }
  
  clearHistory() {
    // Clear messages array
    this.messages = [];
    
    // Clear UI
    if (this.messagesContainer) {
      this.messagesContainer.innerHTML = '';
    }
    
    // Clear sessionStorage
    if (this.enablePersistence) {
      sessionStorage.removeItem('frank-chat-conversation');
    }
  }
  
  escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }
}

// NOTE: Auto-initialization disabled when using web component
